class AuthenticationManager extends ChangeNotifier {
  SharedPreferences? _prefs;

  String? _authToken;
  String? _userId;

  String? get authToken => _authToken;
  String? get userId => _userId;

  Future<void> initialize() async {
    _prefs = await SharedPreferences.getInstance();
    _authToken = _prefs!.getString('authToken');
    _userId = _prefs!.getString('userId');
    notifyListeners();
  }

  Future<void> login(String email, String password) async {
    // Perform login logic here
    // ...

    // Save auth tokens and user data
    await _prefs!.setString('authToken', 'YOUR_AUTH_TOKEN');
    await _prefs!.setString('userId', 'YOUR_USER_ID');

    _authToken = _prefs!.getString('authToken');
    _userId = _prefs!.getString('userId');
